namespace sv_44eccff6358b48a19ca74fedca29aa67.Services;

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_44eccff6358b48a19ca74fedca29aa67.Services

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text small text-muted mb-1">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center">
            <div>
                <span class="badge @PriorityClass">@Task.Priority</span>
                <span class="small text-muted ms-1">@Task.DueDate.ToString("MMM dd")</span>
            </div>
            <div>
                @if (LeftStatus is not null)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                            @onclick="MoveLeft" disabled="@IsMoving"
                            title="Move to @LeftStatus">◀</button>
                }
                @if (RightStatus is not null)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1 ms-1"
                            @onclick="MoveRight" disabled="@IsMoving"
                            title="Move to @RightStatus">▶</button>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMove { get; set; }

    private bool IsMoving;

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveLeft()
    {
        if (LeftStatus is null) return;
        IsMoving = true;
        await OnMove.InvokeAsync((Task.Id, LeftStatus));
        IsMoving = false;
    }

    private async Task MoveRight()
    {
        if (RightStatus is null) return;
        IsMoving = true;
        await OnMove.InvokeAsync((Task.Id, RightStatus));
        IsMoving = false;
    }
}

@using sv_44eccff6358b48a19ca74fedca29aa67.Services

<div class="kanban-column">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@Status</h5>
            <span class="badge bg-secondary rounded-pill">@Tasks.Count</span>
        </div>
        <div class="card-body kanban-card-body">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          LeftStatus="@LeftStatus"
                          RightStatus="@RightStatus"
                          OnMove="OnMoveTask" />
            }

            @if (showForm)
            {
                <AddTaskForm OnSave="HandleSave" OnCancel="HandleCancel" />
            }
            else
            {
                <button class="btn btn-sm btn-outline-primary w-100 mt-2" @onclick="() => showForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = "";
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnCreateTask { get; set; }

    private bool showForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        await OnCreateTask.InvokeAsync((args.Title, args.Assignee, args.Priority, args.DueDate, Status));
        showForm = false;
    }

    private void HandleCancel()
    {
        showForm = false;
    }
}

@page "/board"
@using sv_44eccff6358b48a19ca74fedca29aa67.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />

    <div class="mb-3">
        <input type="text"
               class="form-control"
               placeholder="Search tasks by title..."
               @bind="searchTerm"
               @bind:event="oninput" />
    </div>

    <div class="row g-3">
        <KanbanColumn Status="To Do"
                      Tasks="@GetFilteredTasks("To Do")"
                      LeftStatus="@null"
                      RightStatus="In Progress"
                      OnMoveTask="HandleMoveTask"
                      OnCreateTask="HandleCreateTask" />

        <KanbanColumn Status="In Progress"
                      Tasks="@GetFilteredTasks("In Progress")"
                      LeftStatus="To Do"
                      RightStatus="Done"
                      OnMoveTask="HandleMoveTask"
                      OnCreateTask="HandleCreateTask" />

        <KanbanColumn Status="Done"
                      Tasks="@GetFilteredTasks("Done")"
                      LeftStatus="In Progress"
                      RightStatus="@null"
                      OnMoveTask="HandleMoveTask"
                      OnCreateTask="HandleCreateTask" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.First(t => t.Id == args.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = args.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleCreateTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);

            // If the task was created in a column other than its default status, update it
            if (newTask.Status != args.Status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, args.Status);
                newTask = newTask with { Status = args.Status };
            }

            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

::deep .kanban-column {
    min-width: 0;
    flex: 1;
}

::deep .kanban-card-body {
    min-height: 300px;
    max-height: 70vh;
    overflow-y: auto;
}

