@using sv_44eccff6358b48a19ca74fedca29aa67.Services

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text small text-muted mb-1">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center">
            <div>
                <span class="badge @PriorityClass">@Task.Priority</span>
                <span class="small text-muted ms-1">@Task.DueDate.ToString("MMM dd")</span>
            </div>
            <div>
                @if (LeftStatus is not null)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1"
                            @onclick="MoveLeft" disabled="@IsMoving"
                            title="Move to @LeftStatus">◀</button>
                }
                @if (RightStatus is not null)
                {
                    <button class="btn btn-sm btn-outline-secondary py-0 px-1 ms-1"
                            @onclick="MoveRight" disabled="@IsMoving"
                            title="Move to @RightStatus">▶</button>
                }
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMove { get; set; }

    private bool IsMoving;

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveLeft()
    {
        if (LeftStatus is null) return;
        IsMoving = true;
        await OnMove.InvokeAsync((Task.Id, LeftStatus));
        IsMoving = false;
    }

    private async Task MoveRight()
    {
        if (RightStatus is null) return;
        IsMoving = true;
        await OnMove.InvokeAsync((Task.Id, RightStatus));
        IsMoving = false;
    }
}

