@page "/board"
@using sv_44eccff6358b48a19ca74fedca29aa67.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />

    <div class="mb-3">
        <input type="text"
               class="form-control"
               placeholder="Search tasks by title..."
               @bind="searchTerm"
               @bind:event="oninput" />
    </div>

    <div class="row g-3">
        <KanbanColumn Status="To Do"
                      Tasks="@GetFilteredTasks("To Do")"
                      LeftStatus="@null"
                      RightStatus="In Progress"
                      OnMoveTask="HandleMoveTask"
                      OnCreateTask="HandleCreateTask" />

        <KanbanColumn Status="In Progress"
                      Tasks="@GetFilteredTasks("In Progress")"
                      LeftStatus="To Do"
                      RightStatus="Done"
                      OnMoveTask="HandleMoveTask"
                      OnCreateTask="HandleCreateTask" />

        <KanbanColumn Status="Done"
                      Tasks="@GetFilteredTasks("Done")"
                      LeftStatus="In Progress"
                      RightStatus="@null"
                      OnMoveTask="HandleMoveTask"
                      OnCreateTask="HandleCreateTask" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.First(t => t.Id == args.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = args.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleCreateTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);

            // If the task was created in a column other than its default status, update it
            if (newTask.Status != args.Status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, args.Status);
                newTask = newTask with { Status = args.Status };
            }

            allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

